class Solution:
    def lexicalOrder(self, n: int) -> List[int]:
        ans, cur = [], 1
        for _ in range(n):
            ans.append(cur)
            if cur * 10 <= n:
                cur *= 10
            elif cur % 10 != 9 and cur + 1 <= n:
                cur += 1
            else:
                cur //= 10
                while cur % 10 == 9:
                    cur //= 10
                cur += 1
        return ans

