int* lexicalOrder(int n, int* retSize) {
    int* ans = malloc(n * sizeof(int)); *retSize = n;
    int cur = 1;
    for (int i = 0; i < n; i++) {
        ans[i] = cur;
        if (cur * 10 <= n) cur *= 10;
        else if (cur % 10 != 9 && cur + 1 <= n) cur++;
        else { cur /= 10; while (cur % 10 == 9) cur /= 10; cur++; }
    }
    return ans;
}
